from __future__ import annotations
import functools
import logging
import threading
from typing import Any, Callable, Iterator, Protocol, Set


class BenchmarkHook(Protocol):
    def on_call_start(self, layer: str, plugin_name: str, method: str, args: tuple, kwargs: dict) -> Any: ...
    def on_call_end(self, context: Any, result: Any, error: Exception | None) -> None: ...

class CachingHook(Protocol):
    def get_cached_result(self, layer: str, plugin_name: str, method: str, args: tuple, kwargs: dict) -> Any: ...
    def cache_result(self, layer:
str, plugin_name: str, method: str, args: tuple, kwargs: dict, result: Any) -> None: ...


_ NO_CACHE = object()
_hooks: list[BenchmarkHook] = []
_hooks_lock = threading.Lock()  # [VERIFY] method not found in signatures

def register_hook(hook: BenchmarkHook) -> None:
    with _hooks_lock:
        _hooks.append(hook)

def unregister_hook(hook: BenchmarkHook) -> None:
    with _hooks_lock:
        try:
            _hooks.remove(hook)
        except ValueError:
            pass

def clear_hooks() -> None:
    with _hooks_lock:
        _hooks.clear()

def has_hooks() -> bool:
    return len(_hooks) > 0

def get_hooks() -> list[BenchmarkHook]:
    return _hooks.copy()

class InstrumentedProxy:
    def __init__(self, target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None = None):
        self._target = target
        self._layer = layer
        self._plugin_name = plugin_name
        self._methods_to_track = methods_to_track or set()

    def __getattr__(self, name: str) -> Any:
        attr = getattr(self._target, name)
        if name in self._methods_to_track and callable(attr):
            return self._wrap_method(attr, name)
        return attr

    def _wrap_method(self, method: Callable, method_name: str) -> Callable:
        @functools.wraps(method)  # [VERIFY] method not found in signatures
        def wrapper(*args, **kwargs):
            context = None
            error = None
            try:
                for hook in get_hooks():
                    context = hook.on_call_start(self._layer, self._plugin_name, method_name, args, kwargs)
                result = method(*args, **kwargs)
                for hook in get_hooks():
                    hook.on_call_end(context, result, error)
            except Exception as e:
                error = e
                for hook in get_hooks():
                    hook.on_call_end(context, None, error)
                raise
            return result
        return wrapper

    def __repr__(self) -> str:
        return f"InstrumentedProxy({self._target!r})"

    def __str__(self) -> str:
        return str(self._target)

def maybe_wrap(target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None = None) -> Any:
    if has_hooks():
        return InstrumentedProxy(target, layer, plugin_name, methods_to_track)
    return target

def wrap(target: Any, layer: str, plugin_name: str, methods_to_track: set[str] | None = None) -> InstrumentedProxy:
    return InstrumentedProxy(target, layer, plugin_name, methods_to_track)

